#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int r,c;
int a[132][123];
bool vis[463][426];
int fx[5]={0,0,1,0,-1};
int fy[5]={0,1,0,-1,0};
int dfs(int x,int y,int ans)
{
	if(x==r&&y==c)
		return ans;
	vis[x][y]=1;
	int xx,yy,an=0;
	FOR(i,1,4)
    {
		int tx=x+fx[i];
		int ty=y+fy[i];
		if(a[tx][ty]>an&&tx>0&&ty>0&&tx<=r&&ty<=c&&vis[tx][ty]==0)
        {
			an=a[tx][ty];xx=tx,yy=ty;
		}
	}
	return dfs(xx,yy,ans+an);
}
signed main(void)
{
	r=read(),c=read();
	FOR(i,1,r)
    {
		FOR(j,1,c)
        {
			cin>>a[i][j];
		}
	}
	write(dfs(1,1,a[1][1]));
	return false;
}
